> The failures are on podman-remote.

**EDIT:** I looked at the last PR again and it is `make remoteintegration` I should have used to test `podman-remote`

Oh yeah.... I remember @Luap99 mentioning this on my last PR. I thought I ran the `make localunit` (which I thought tested podman-remote) target before I opened this PR :thinking:, my bad.

I think I have the fix but I want to try to test it / think more about its implementation. I'll work on it tonight after work.

Here's what I think will work at the moment.
```
diff --git a/pkg/bindings/system/system.go b/pkg/bindings/system/system.go
index 1203f5c3c..c39a9b9ba 100644
--- a/pkg/bindings/system/system.go
+++ b/pkg/bindings/system/system.go
@@ -13,6 +13,7 @@ import (
        "github.com/containers/podman/v2/libpod/define"
        "github.com/containers/podman/v2/pkg/bindings"
        "github.com/containers/podman/v2/pkg/domain/entities"
+       "github.com/containers/podman/v2/pkg/domain/filters"
        "github.com/pkg/errors"
        "github.com/sirupsen/logrus"
 )
@@ -74,7 +75,7 @@ func Events(ctx context.Context, eventChan chan entities.Event, cancelChan chan
 }

 // Prune removes all unused system data.
-func Prune(ctx context.Context, all, volumes *bool) (*entities.SystemPruneReport, error) {
+func Prune(ctx context.Context, opts entities.SystemPruneOptions) (*entities.SystemPruneReport, error) {
        var (
                report entities.SystemPruneReport
        )
@@ -83,12 +84,20 @@ func Prune(ctx context.Context, all, volumes *bool) (*entities.SystemPruneReport
                return nil, err
        }
        params := url.Values{}
-       if all != nil {
-               params.Set("All", strconv.FormatBool(*all))
+       params.Set("All", strconv.FormatBool(opts.All))
+       params.Set("Volumes", strconv.FormatBool(opts.Volume))
+       filterMap, err := filters.ParseFilterArgumentsIntoFilters(opts.Filter)
+       if err != nil {
+               return nil, err
        }
-       if volumes != nil {
-               params.Set("Volumes", strconv.FormatBool(*volumes))
+       if len(opts.Filter) > 0 {
+               strFilters, err := bindings.FiltersToString(filterMap)
+               if err != nil {
+                       return nil, err
+               }
+               params.Set("filters", strFilters)
        }
+
```

